class Solution:
    def solve(self, A, T) -> int:
        n = len(A)
        dp = [0] * (T + 1)

        for i in range(1, n + 1):
            for j in range(A[i-1], T + 1):
                dp[j] = min(dp[j], dp[j - A[i-1]] + 1)

        return dp[-1]

    def print(self, output):
        print(output)

    def main(self):
        A = [1, 2, 5]
        T = 10
        output = self.solve(A, T)
        self.print(output)

if __name__ == '__main__':
    solution = Solution()
    solution.main()

