#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    int solve(vector<int>& A, int T) {
        int n = A.size();
        vector<int> dp(T + 1, 0);

        for (int i = 1; i <= n; i++) {
            for (int j = A[i - 1]; j <= T; j++)
                dp[j] = min(dp[j], dp[j - A[i - 1]] + 1);
        }

        return dp.back();
    }
};
int main() {
    Solution s;
    vector<int> A = {1, 2, 5};
    int T = 10;
    int output = s.solve(A, T);
    cout << output << endl;
    return 0;
}
